script:
frappe.ui.form.on("Hostel Leaves", {

    refresh(frm) {

        // Default Approval Status
        if (frm.is_new() && !frm.doc.approval_status) {
            frm.set_value("approval_status", "Pending");
        }

    },

    student(frm) {

        if (!frm.doc.student) return;

        // Fetch Student Name and Parent Contact
        frappe.db.get_value(
            "Student",
            frm.doc.student,
            ["student_name", "mobile_number"],
            function(r) {

                if (r) {

                    if (r.student_name) {
                        frm.set_value("student_name", r.student_name);
                    }

                    if (r.mobile_number) {
                        frm.set_value("parent_contact", r.mobile_number);
                    }
                }

            }
        );

        // Fetch Active Hostel Admission
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Hostel Admission",
                filters: {
                    student: frm.doc.student,
                    admission_status: "Active"
                },
                fields: ["name"],
                limit_page_length: 1
            },
            callback: function(r) {

                if (r.message.length) {

                    frm.set_value("hostel_admission", r.message[0].name);

                } else {

                    frappe.msgprint("No Active Hostel Admission found.");

                    frm.set_value("hostel_admission", "");

                }

            }
        });

    },

    to_date(frm) {

        if (frm.doc.from_date &&
            frm.doc.to_date &&
            frm.doc.to_date < frm.doc.from_date) {

            frappe.msgprint("To Date cannot be earlier than From Date.");

            frm.set_value("to_date", "");

        }

    }

});
